56	    // Some EP hybrid mode settings
57	    static constexpr int kNumMaxChannelsPerSM = 8;
58	    static constexpr int kNumMaxSMs = 160;
59	    static constexpr int kNumMaxChannels = kNumMaxChannelsPerSM * kNumMaxSMs;
60	
61	    // Some Engram storage settings
62	    int num_engram_entries = 0, engram_hidden = 0;
63	    std::optional<torch::Tensor> engram_sf;
64	
65	    // PP settings
66	    int prev_rank_idx = 0, next_rank_idx = 0;
67	    int64_t num_max_pp_tensor_bytes = 0;
68	    int num_max_pp_inflight_tensors = 0;
69	
70	    // AGRS session settings
71	    int64_t num_max_agrs_session_bytes = 0;
72	    int num_max_agrs_per_session = 0;
73	    int agrs_session_idx = 0;
74	    bool agrs_in_session = false;
75	
76	    // AGRS in-session settings
77	    int64_t agrs_buffer_offset = 0;
78	    int agrs_buffer_slot_idx = 0;
79	
80	public:
81	    ElasticBuffer(const int& rank_idx, const int& num_ranks,
82	                  const int64_t& nccl_comm, const symmetric::cpu_comm_t& cpu_comm,
83	                  const int64_t& num_buffer_bytes, const int64_t& num_cpu_buffer_bytes,
84	                  const bool& allow_hybrid_mode,
85	                  const bool& allow_multiple_reduction,
86	                  const bool& prefer_overlap_with_compute,
87	                  const int& sl_idx, const int& num_allocated_qps,
88	                  const int& num_cpu_timeout_secs, const int& num_gpu_timeout_secs,
89	                  const bool& explicitly_destroy):
90	        num_buffer_bytes(num_buffer_bytes),
91	        num_cpu_buffer_bytes(num_cpu_buffer_bytes),
92	        explicitly_destroy(explicitly_destroy),
93	        comm_stream(get_global_comm_stream()),
94	        allow_hybrid_mode(allow_hybrid_mode),
95	        allow_multiple_reduction(allow_multiple_reduction),
96	        prefer_overlap_with_compute(prefer_overlap_with_compute) {
97	        // Check buffer bytes alignment (2 MB)
98	        EP_HOST_ASSERT(num_buffer_bytes > 0 and num_buffer_bytes % symmetric::kNumAlignmentBytes == 0);
99	        EP_HOST_ASSERT(num_cpu_buffer_bytes >= 0 and num_cpu_buffer_bytes % symmetric::kNumAlignmentBytes == 0);
100	        EP_HOST_ASSERT(num_cpu_buffer_bytes <= num_buffer_bytes);
101	        num_gpu_buffer_bytes = num_buffer_bytes - num_cpu_buffer_bytes;
102	
103	        // Workspace is aligned to 2 MB so that it sits cleanly at the front of the GPU segment
104	        const auto num_workspace_bytes = math::align<int64_t>(
105	            layout::WorkspaceLayout::get_num_bytes(), symmetric::kNumAlignmentBytes);
106	
107	        // Create NCCL symmetric memory context
108	        // Symmetric memory layout: [[[Workspace] GPU buffer] CPU buffer]
109	        // sym.num_bytes = workspace + buffer, sym.num_cpu_bytes = CPU buffer
110	        const auto num_sym_bytes = num_workspace_bytes + num_buffer_bytes;
111	        this->nccl_context = std::make_shared<nccl::NCCLSymmetricMemoryContext>(
112	            nccl_comm, cpu_comm, num_ranks, rank_idx,
113	            num_sym_bytes, num_cpu_buffer_bytes,
114	            allow_hybrid_mode, sl_idx, num_allocated_qps);
115	
116	        // Verify the symmetric memory layout matches our expectations
117	        EP_HOST_ASSERT(num_workspace_bytes + num_gpu_buffer_bytes == nccl_context->num_gpu_bytes);
118	        EP_HOST_ASSERT(num_cpu_buffer_bytes == nccl_context->num_cpu_bytes);
119	
120	        // Timeout
121	        this->num_cpu_timeout_secs = num_cpu_timeout_secs;
122	        this->num_gpu_timeout_cycles = static_cast<int64_t>(num_gpu_timeout_secs);
123	        this->num_gpu_timeout_cycles *= jit::device_runtime->get_clock_rate();
124	
125	        // Assign workspaces and buffers
126	        workspace = this->nccl_context->mapped_window_ptr;
127	        workspace_layout_wo_expert = std::make_shared<layout::WorkspaceLayout>(
128	            workspace, nccl_context->num_scaleout_ranks, nccl_context->num_scaleup_ranks, 0);
129	        buffer = static_cast<uint8_t*>(workspace) + num_workspace_bytes;
130	        CUDA_RUNTIME_CHECK(cudaMemset(workspace, 0, num_workspace_bytes));
131	
132	        // Allocate host workspaces
133	        CUDA_RUNTIME_CHECK(cudaMallocHost(&host_workspace, layout::WorkspaceLayout::get_num_bytes(), cudaHostAllocMapped));
134	        CUDA_RUNTIME_CHECK(cudaHostGetDevicePointer(&mapped_host_workspace, host_workspace, 0));
135	        std::memset(host_workspace, 0, layout::WorkspaceLayout::get_num_bytes());
136	
137	        // We should call a barrier at the end
138	        // The barrier should be called by Python `dist.barrier`
139	        // NOTES: do not call our barrier, as the workspace is not ready yet
140	    }
141	
142	    ~ElasticBuffer() noexcept(false) {
143	        if (not explicitly_destroy)
144	            destroy();
145	
146	        if (not destroyed) {
147	            printf("`destroy()` is not called before DeepEP elastic buffer destruction, which can leak resources.\n");
148	            fflush(stdout);
149	        }
150	    }
151	
152	    void destroy() {
153	        EP_HOST_ASSERT(not destroyed);
154	
155	        // Finish all works on all GPUs
156	        barrier(true, true);
157	
158	        // Deallocate host workspaces
159	        CUDA_RUNTIME_CHECK(cudaFreeHost(host_workspace));
160	
161	        // Destroy NCCL context
162	        nccl_context->finalize();
163	
164	        // Cannot use anymore
165	        destroyed = true;
166	    }
167	
168	    torch::Stream get_comm_stream() const {
169	        return comm_stream;
170	    }
171	
172	    std::tuple<int, int> get_physical_domain_size() const {
173	        return {nccl_context->num_rdma_ranks, nccl_context->num_nvl_ranks};
174	    }
175	
176	    std::tuple<int, int> get_logical_domain_size() const {
177	        return {nccl_context->num_scaleout_ranks, nccl_context->num_scaleup_ranks};
178	    }
179	
180	    // ReSharper disable once CppMemberFunctionMayBeStatic
181	    void barrier(const bool& use_comm_stream, const bool& with_cpu_sync, const bool& sequential = true) const {
182	        const auto compute_stream = at::cuda::getCurrentCUDAStream();
183	        const auto stream = use_comm_stream ? comm_stream : compute_stream;
184	        if (use_comm_stream)
185	            stream_wait(comm_stream, compute_stream);
186	
187	        // Wait all streams to finish on this GPU
188	        if (with_cpu_sync)
189	            CUDA_RUNTIME_CHECK(cudaDeviceSynchronize());
190	
191	        // Launch GPU barrier
192	        launch_barrier(nccl_context->dev_comm, nccl_context->window,
193	                       workspace,
194	                       nccl_context->scaleout_rank_idx, nccl_context->scaleup_rank_idx,
195	                       nccl_context->num_scaleout_ranks, nccl_context->num_scaleup_ranks,
196	                       num_gpu_timeout_cycles,
197	                       nccl_context->is_scaleup_nvlink,
198	                       sequential,
199	                       stream);
200	
201	        // Let CPU wait
202	        if (with_cpu_sync)
203	            CUDA_RUNTIME_CHECK(cudaDeviceSynchronize());
204	
205	        // Compute stream should also wait for the barrier
206	        if (use_comm_stream)
207	            stream_wait(compute_stream, comm_stream);
208	    }
209	
210	    void engram_write(const torch::Tensor& storage, const std::optional<torch::Tensor>& sf) {
211	        // Ensure previous fetch are finished
212	        barrier(false, true);
213	
214	        const auto compute_stream = at::cuda::getCurrentCUDAStream();
215	
216	        // Check storage
217	        const auto [num_entries, hidden] = get_shape<2>(storage);
218	        EP_HOST_ASSERT(storage.scalar_type() == torch::kBFloat16 or
219	                       storage.scalar_type() == torch::kFloat8_e4m3fn);
220	        EP_HOST_ASSERT(storage.is_cuda() and storage.is_contiguous());
221	        num_engram_entries = num_entries, engram_hidden = hidden;
222	
223	        // Store globally-replicated FP8 scaling factors for local gather during fetch.
224	        if (sf.has_value())
225	            EP_HOST_ASSERT(sf->dim() == 2 and sf->is_cuda() and sf->is_contiguous() and
226	                           sf->element_size() == sizeof(sf_pack_t));
227	        engram_sf = sf;
228	
229	        // Write storage to CPU segment at back of buffer
230	        EP_HOST_ASSERT(storage.nbytes() <= num_cpu_buffer_bytes and "Engram storage exceeds CPU buffer size");
231	        const auto cpu_write_offset = allow_hybrid_mode
232	            ? static_cast<int64_t>(nccl_context->scaleup_rank_idx) * num_cpu_buffer_bytes : 0;
233	        CUDA_RUNTIME_CHECK(cudaMemcpyAsync(
234	            math::advance_ptr(buffer, num_gpu_buffer_bytes + cpu_write_offset),
235	            storage.data_ptr(), storage.nbytes(),
236	            cudaMemcpyDeviceToDevice, compute_stream));
237	
238	        // Ensure data is visible for all ranks
239	        barrier(false, true);
240	    }
241	
242	    std::function<std::tuple<torch::Tensor, std::optional<torch::Tensor>>()>
243	    engram_fetch(const torch::Tensor& indices, int num_qps, const bool& use_tma_aligned_col_major_sf) const {
244	        const auto use_fp8 = engram_sf.has_value();
245	        const auto fetched_dtype = use_fp8 ? torch::kFloat8_e4m3fn : torch::kBFloat16;
246	        const int elem_size = use_fp8 ? sizeof(__nv_fp8_e4m3) : sizeof(nv_bfloat16);
247	        const auto [num_tokens, num_entries_per_token] = get_shape<2>(indices);
248	        EP_HOST_ASSERT(indices.scalar_type() == torch::kInt);
249	        EP_HOST_ASSERT(indices.is_cuda() and indices.is_contiguous());
250	        EP_HOST_ASSERT(num_tokens * num_entries_per_token * engram_hidden * elem_size <= num_gpu_buffer_bytes);
251	
252	        // Calculate a QP count
253	        if (num_qps == 0)
254	            num_qps = nccl_context->num_allocated_qps;
255	
256	        // Return tensor from the raw buffer: each token's entries are concatenated along hidden
257	        EP_HOST_ASSERT(num_engram_entries > 0);
258	        const auto fetched = torch::from_blob(
259	            buffer,
260	            {num_tokens, engram_hidden * num_entries_per_token},
261	            torch::TensorOptions().dtype(fetched_dtype).device(torch::kCUDA)
262	        );
263	
264	        auto fetched_sf = std::optional<torch::Tensor>();
265	        void* sf_table_ptr = nullptr;
266	        void* fetched_sf_ptr = nullptr;
267	        int num_sf_packs = 0, sf_token_stride = 0, sf_hidden_stride = 0;
268	        if (use_fp8) {
269	            num_sf_packs = static_cast<int>(engram_sf->size(1));
270	            if (use_tma_aligned_col_major_sf) {
271	                // TMA-aligned column-major layout for the next GEMM input
272	                sf_token_stride = 1, sf_hidden_stride = math::align(num_tokens, kNumAlignedSFPacks);
273	            } else {
274	                sf_token_stride = num_entries_per_token * num_sf_packs, sf_hidden_stride = 1;
275	            }
276	            fetched_sf = torch::empty_strided({num_tokens, num_entries_per_token * num_sf_packs},
277	                                              {sf_token_stride, sf_hidden_stride}, engram_sf->options());
278	            sf_table_ptr = engram_sf->data_ptr();
279	            fetched_sf_ptr = fetched_sf->data_ptr();
280	        }
281	
282	        // Last issued Gin requests
283	        const auto num_gin_ranks = allow_hybrid_mode
284	            ? nccl_context->num_scaleout_ranks
285	            : nccl_context->num_ranks;
286	        const auto last_gin_requests = torch::empty(
287	            {num_gin_ranks * num_qps, sizeof(ncclGinRequest_t)},
288	            torch::TensorOptions().dtype(torch::kByte).device(torch::kCUDA)
289	        );
290	
291	        // Launch the fetch kernel
292	        launch_engram_fetch(
293	            nccl_context->dev_comm, nccl_context->window,
294	            math::advance_ptr(buffer, num_gpu_buffer_bytes),
295	            fetched.data_ptr(),
296	            indices.data_ptr<int>(),
297	            static_cast<ncclGinRequest_t*>(last_gin_requests.data_ptr()),
298	            sf_table_ptr, fetched_sf_ptr, sf_token_stride, sf_hidden_stride,
299	            num_engram_entries,
300	            engram_hidden, elem_size, num_sf_packs,
301	            num_entries_per_token,
302	            num_tokens,
303	            nccl_context->num_scaleout_ranks,
304	            nccl_context->num_scaleup_ranks,
305	            num_cpu_buffer_bytes,
306	            num_qps,
307	            allow_hybrid_mode,
308	            at::cuda::getCurrentCUDAStream()
309	        );
310	
311	        return [=, this]() -> std::tuple<torch::Tensor, std::optional<torch::Tensor>> {
312	            // Wait for all RDMA gets to complete
313	            launch_engram_fetch_wait(
314	                static_cast<ncclGinRequest_t*>(last_gin_requests.data_ptr()),
315	                nccl_context->dev_comm,
316	                nccl_context->window,
317	                nccl_context->num_scaleout_ranks,
318	                nccl_context->num_scaleup_ranks,
319	                num_qps,
320	                allow_hybrid_mode,
321	                at::cuda::getCurrentCUDAStream()
322	            );
323	            return {fetched, fetched_sf};
324	        };
